1608	
1609	\leanok
1610	[(iii-1) Unit expansion: inverting the comp-coherence]
1611	  \label{lem:base_change_mate_fstar_reindex_legs_unitExpand}
1612	  \lean{AlgebraicGeometry.base_change_mate_fstar_reindex_legs_unitExpand}
1613	  \uses{lem:pullbackPushforward_unit_comp}
1614	  Let \(e : X' \xrightarrow{\sim} \operatorname{Spec}(A \otimes_R R')\) be the canonical
1615	  isomorphism, \(\iota_A : A \to A \otimes_R R'\) the left tensor inclusion, and set
1616	  \(g' = e \circ \operatorname{Spec}\iota_A\). For an \(A\)-module \(M\), the bare \((g')\)-unit
1617	  \(\eta^{g'}_{\widetilde M}\) of the \((g')\)-adjunction expands as the four-factor composite
1618	  \[
1619	    \eta^{g'}_{\widetilde M}
1620	      \;=\;
1621	      \eta^{\operatorname{Spec}\iota_A}_{\widetilde M}
1622	      \,\circ\, (\operatorname{Spec}\iota_A)_{*}\bigl(\eta^{e}_{(\operatorname{Spec}\iota_A)^{*}\widetilde M}\bigr)
1623	      \,\circ\, (\mathrm{pushforwardComp}_{e,\operatorname{Spec}\iota_A})^{\mathrm{hom}}_{\widetilde M}
1624	      \,\circ\, (g')_{*}\bigl((\mathrm{pullbackComp}_{e,\operatorname{Spec}\iota_A})^{\mathrm{hom}}_{\widetilde M}\bigr),
1625	  \]
1626	  where composites are read left to right.
1627	\end{lemma}
1628	\begin{proof}
1629	  \uses{lem:pullbackPushforward_unit_comp}
1630	  The leg-reindex engine Lemma~\ref{lem:pullbackPushforward_unit_comp}, instantiated at \(a = e\),
1631	  \(b = \operatorname{Spec}\iota_A\), \(N = \widetilde M\), reads
1632	  \[
1633	    \eta^{\operatorname{Spec}\iota_A}_{\widetilde M}
1634	      \circ (\operatorname{Spec}\iota_A)_{*}(\eta^{e})
1635	      \circ (\mathrm{pushforwardComp}_{e,\operatorname{Spec}\iota_A})^{\mathrm{hom}}
1636	    \;=\;
1637	    \eta^{g'}_{\widetilde M}
1638	      \circ (g')_{*}\bigl((\mathrm{pullbackComp}_{e,\operatorname{Spec}\iota_A})^{\mathrm{inv}}\bigr).
1639	  \]
1640	  Post-compose both sides with \((g')_{*}\bigl((\mathrm{pullbackComp}_{e,\operatorname{Spec}\iota_A})^{\mathrm{hom}}\bigr)\).
1641	  Since \((g')_{*}\) is a functor it carries
1642	  \((\mathrm{pullbackComp})^{\mathrm{inv}} \circ (\mathrm{pullbackComp})^{\mathrm{hom}} = \mathrm{id}\)
1643	  to the identity, so the right-hand side collapses to \(\eta^{g'}_{\widetilde M}\), giving the stated
1644	  expansion.
1645	\end{proof}
